package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Method;
import java.util.Arrays;
import java.util.Collections;
import java.util.List;

import com.google.gson.ReflectionAccessFilter;
import com.google.gson.ReflectionAccessFilter.FilterResult;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method as ReflectMethod;

class ReflectionAccessFilterHelperTest {

  private AccessibleObject accessibleObject;
  private Object targetObject;

  @BeforeEach
  void setup() {
    accessibleObject = mock(AccessibleObject.class);
    targetObject = new Object();
  }

  @Test
  void testIsJavaType_class() throws Exception {
    // Using reflection to invoke private static boolean isJavaType(String)
    ReflectMethod method = ReflectionAccessFilterHelper.class.getDeclaredMethod("isJavaType", String.class);
    method.setAccessible(true);

    // Known java type
    boolean result = (boolean) method.invoke(null, "java.lang.String");
    assertTrue(result);

    // Non-java type
    result = (boolean) method.invoke(null, "com.example.MyClass");
    assertFalse(result);
  }

  @Test
  void testIsJavaType_class_public() {
    assertTrue(ReflectionAccessFilterHelper.isJavaType(String.class));
    assertFalse(ReflectionAccessFilterHelper.isJavaType(Object.class.getClassLoader() != null ? Object.class : com.google.gson.internal.ReflectionAccessFilterHelper.class)); // just to test false path
  }

  @Test
  void testIsAndroidType_class() throws Exception {
    ReflectMethod method = ReflectionAccessFilterHelper.class.getDeclaredMethod("isAndroidType", String.class);
    method.setAccessible(true);

    // Android type example
    boolean result = (boolean) method.invoke(null, "android.app.Activity");
    assertTrue(result);

    // Non-android type
    result = (boolean) method.invoke(null, "java.lang.String");
    assertFalse(result);
  }

  @Test
  void testIsAndroidType_class_public() {
    assertTrue(ReflectionAccessFilterHelper.isAndroidType(android.app.Activity.class));
    assertFalse(ReflectionAccessFilterHelper.isAndroidType(String.class));
  }

  @Test
  void testIsAnyPlatformType() {
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(String.class));
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(android.app.Activity.class));
    assertFalse(ReflectionAccessFilterHelper.isAnyPlatformType(com.google.gson.internal.ReflectionAccessFilterHelper.class));
  }

  @Test
  void testGetFilterResult_noFilters() {
    List<ReflectionAccessFilter> filters = Collections.emptyList();
    FilterResult result = ReflectionAccessFilterHelper.getFilterResult(filters, String.class);
    assertEquals(FilterResult.UNDECIDED, result);
  }

  @Test
  void testGetFilterResult_filters() {
    ReflectionAccessFilter filter1 = mock(ReflectionAccessFilter.class);
    ReflectionAccessFilter filter2 = mock(ReflectionAccessFilter.class);

    when(filter1.apply(String.class)).thenReturn(FilterResult.UNDECIDED);
    when(filter2.apply(String.class)).thenReturn(FilterResult.ALLOW);

    List<ReflectionAccessFilter> filters = Arrays.asList(filter1, filter2);
    FilterResult result = ReflectionAccessFilterHelper.getFilterResult(filters, String.class);
    assertEquals(FilterResult.ALLOW, result);

    verify(filter1).apply(String.class);
    verify(filter2).apply(String.class);
  }

  @Test
  void testGetFilterResult_filters_denied() {
    ReflectionAccessFilter filter1 = mock(ReflectionAccessFilter.class);
    ReflectionAccessFilter filter2 = mock(ReflectionAccessFilter.class);

    when(filter1.apply(String.class)).thenReturn(FilterResult.DENY);
    when(filter2.apply(String.class)).thenReturn(FilterResult.ALLOW);

    List<ReflectionAccessFilter> filters = Arrays.asList(filter1, filter2);
    FilterResult result = ReflectionAccessFilterHelper.getFilterResult(filters, String.class);
    assertEquals(FilterResult.DENY, result);

    verify(filter1).apply(String.class);
    verifyNoMoreInteractions(filter2);
  }

  @Test
  void testCanAccess_accessibleObjectIsNull() {
    assertFalse(ReflectionAccessFilterHelper.canAccess(null, targetObject));
  }

  @Test
  void testCanAccess_accessibleObjectSetAccessibleTrue() throws Exception {
    when(accessibleObject.isAccessible()).thenReturn(true);
    assertTrue(ReflectionAccessFilterHelper.canAccess(accessibleObject, targetObject));
  }

  @Test
  void testCanAccess_accessibleObjectSetAccessibleFalse() throws Exception {
    when(accessibleObject.isAccessible()).thenReturn(false);
    doNothing().when(accessibleObject).setAccessible(true);
    assertTrue(ReflectionAccessFilterHelper.canAccess(accessibleObject, targetObject));
    verify(accessibleObject).setAccessible(true);
  }

  @Test
  void testCanAccess_setAccessibleThrows() throws Exception {
    when(accessibleObject.isAccessible()).thenReturn(false);
    doThrow(new SecurityException()).when(accessibleObject).setAccessible(true);
    assertFalse(ReflectionAccessFilterHelper.canAccess(accessibleObject, targetObject));
  }
}
